previewCss:
.darma-loader-darma-custom-288 {
  width: fit-content;
  font-size: 34px;
  font-family: system-ui,sans-serif;
  font-weight: bold;
  text-transform: uppercase;
  color: #0000;
  -webkit-text-stroke: 1px var(--loader-color, #9333ea);
  background: linear-gradient(90deg,var(--loader-color, #9333ea),var(--loader-secondary-color, #f0abfc)) 0/0% 100% no-repeat text;
  animation: darma-loader-darma-custom-288-l1 1s linear infinite;
}
.darma-loader-darma-custom-288:before {
  content: "Loading";
}
@keyframes darma-loader-darma-custom-288-l1 {
  to{background-size: 120% 100%}
}

